/* Responsive */
@media (max-width: 860px) {
  .featured-grid { grid-template-columns: 1fr; }
  .featured-card { border-right: 0; }
  .stream > * { grid-column: span 12 !important; }
  .notes-grid { grid-template-columns: 1fr; }
  .note-row { border-right: 0; }
